from pydantic import BaseModel

app = FastAPI()

class Item(BaseModel):
    name: str

items_db: dict[int, dict] = {}

# Method 1: Default status code in decorator
@app.post("/items/", status_code=status.HTTP_201_CREATED)
def create_item(item: Item):
    items_db[1] = item.model_dump()
    return {"id": 1, **item.model_dump()}

# Method 2: Dynamic status code via Response parameter
@app.put("/items/{item_id}")
def upsert_item(item_id: int, item: Item, response: Response):
    if item_id in items_db:
        response.status_code = status.HTTP_200_OK
    else:
        response.status_code = status.HTTP_201_CREATED
    items_db[item_id] = item.model_dump()
    return {"id": item_id, **item.model_dump()}

# Method 3: HTTPException for errors
@app.get("/items/{item_id}")
def get_item(item_id: int):
    if item_id not in items_db:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail=f"Item {item_id} not found",
        )
    return items_db[item_id]

# Method 4: No content response
@app.delete("/items/{item_id}", status_code=status.HTTP_204_NO_CONTENT)
def delete_item(item_id: int):
    items_db.pop(item_id, None)

